const fs = require('fs');
const path = require('path');

const ROOT = '/home/node/.n8n-files';
const AUDIO_EXT = new Set(['.mp3', '.flac', '.m4a', '.aac', '.ogg', '.opus', '.wav', '.wma', '.aiff', '.alac']);

// 🔄 MODIFICATION ICI : On capte directement la variable "recherche" créée par le schéma n8n
let searchTerm = "";
if (typeof recherche !== 'undefined' && recherche) {
  searchTerm = String(recherche).toLowerCase();
} else if (typeof query !== 'undefined' && query) {
  searchTerm = typeof query === 'string' ? query.toLowerCase() : (query.recherche ? query.recherche.toLowerCase() : "");
}

try {
  function walk(dir) {
    let results = [];
    const entries = fs.readdirSync(dir, { withFileTypes: true });

    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      if (entry.name.startsWith('.')) continue;

      if (entry.isDirectory()) {
        results = results.concat(walk(fullPath));
      } else {
        const ext = path.extname(entry.name).toLowerCase();
        if (AUDIO_EXT.has(ext)) {
          results.push(entry.name);
        }
      }
    }
    return results;
  }

  const toutesLesMusiques = walk(ROOT);

  if (toutesLesMusiques.length === 0) {
    return "Aucune musique trouvée dans la bibliothèque.";
  }

  // Si l'IA cherche quelque chose (ex: "rock"), on filtre la liste
  let musiquesFiltrees = toutesLesMusiques;
  if (searchTerm) {
    musiquesFiltrees = toutesLesMusiques.filter(file => file.toLowerCase().includes(searchTerm));
  }

  if (musiquesFiltrees.length === 0) {
    return `Aucune musique trouvée pour la recherche "${searchTerm}". Demande à l'utilisateur un autre style.`;
  }

  // On limite toujours à 50 résultats maximum pour protéger la RAM
  const echantillon = musiquesFiltrees.sort(() => 0.5 - Math.random()).slice(0, 50);

  const listeFormatee = echantillon.map(file => {
     const nameWithoutExt = file.replace(/\.[^/.]+$/, "");
     return `- ${nameWithoutExt}`;
  });

  if (searchTerm) {
    return `J'ai trouvé ${musiquesFiltrees.length} musiques contenant "${searchTerm}". Voici une sélection :\n\n${listeFormatee.join('\n')}`;
  } else {
    return `Tu as un total de ${toutesLesMusiques.length} musiques. Voici 50 titres au hasard :\n\n${listeFormatee.join('\n')}`;
  }

} catch (error) {
  return `Erreur lors de la lecture du dossier : ${error.message}`;
}
